from collections import deque

class Solution:
    def interactionCosts(self, n, edges, group):
        if n <= 1:
            return 0
        adj = [[] for _ in range(n)]
        for u, v in edges:
            adj[u].append(v)
            adj[v].append(u)
        total = 0
        for src in range(n):
            dist = [-1] * n
            dist[src] = 0
            q = deque([src])
            while q:
                u = q.popleft()
                for v in adj[u]:
                    if dist[v] == -1:
                        dist[v] = dist[u] + 1
                        q.append(v)
            for dst in range(src + 1, n):
                if group[src] == group[dst]:
                    total += dist[dst]
        return total

