        if n <= 1:
            return 0
        adj = [[] for _ in range(n)]
        for u, v in edges:
            adj[u].append(v)
            adj[v].append(u)

        total = [0] * 21
        for g in group:
            total[g] += 1

        parent = [-1] * n
        order = []
        visited = [False] * n
        stack = [0]
        visited[0] = True
        while stack:
            u = stack.pop()
            order.append(u)
            for v in adj[u]:
                if not visited[v]:
                    visited[v] = True
                    parent[v] = u
                    stack.append(v)

        count = [None] * n
        for u in order:
            c = [0] * 21
            c[group[u]] += 1
            count[u] = c

        answer = 0
        for u in reversed(order):
            p = parent[u]
            if p == -1:
                continue
            cu = count[u]
            for g in range(1, 21):
                a = cu[g]
                b = total[g] - a
                answer += a * b
            cp = count[p]
            for g in range(1, 21):
                cp[g] += cu[g]

        return answer

