var interactionCosts = function(n, edges, group) {
    if (n <= 1) return 0;
    const adj = Array.from({ length: n }, () => []);
    for (const [u, v] of edges) {
        adj[u].push(v);
        adj[v].push(u);
    }

    const total = new Array(21).fill(0);
    for (const g of group) total[g]++;

    const parent = new Array(n).fill(-1);
    const order = [];
    const visited = new Array(n).fill(false);
    const stack = [0];
    visited[0] = true;
    while (stack.length) {
        const u = stack.pop();
        order.push(u);
        for (const v of adj[u]) {
            if (!visited[v]) {
                visited[v] = true;
                parent[v] = u;
                stack.push(v);
            }
        }
    }

    const count = new Array(n);
    for (const u of order) {
        const c = new Array(21).fill(0);
        c[group[u]]++;
        count[u] = c;
    }

    let answer = 0;
    for (let i = order.length - 1; i >= 0; i--) {
        const u = order[i];
        const p = parent[u];
        if (p === -1) continue;
        const cu = count[u];
        for (let g = 1; g <= 20; g++) {
            const a = cu[g];
            const b = total[g] - a;
            answer += a * b;
        }
        const cp = count[p];
        for (let g = 1; g <= 20; g++) {
            cp[g] += cu[g];
        }
    }
    return answer;
};
